import{_ as e,o as t,c as r,a2 as n}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"Nanite","description":"","frontmatter":{},"headers":[],"relativePath":"Unreal Engine/Nanite.md","filePath":"Unreal Engine/Nanite.md","lastUpdated":null}'),i={name:"Unreal Engine/Nanite.md"};function l(o,a,s,h,u,p){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="nanite" tabindex="-1">Nanite <a class="header-anchor" href="#nanite" aria-label="Permalink to &quot;Nanite&quot;">​</a></h1><h3 id="nanite-1" tabindex="-1">Nanite <a class="header-anchor" href="#nanite-1" aria-label="Permalink to &quot;Nanite&quot;">​</a></h3><h4 id="mesh-cluster-rendering" tabindex="-1">Mesh Cluster Rendering <a class="header-anchor" href="#mesh-cluster-rendering" aria-label="Permalink to &quot;Mesh Cluster Rendering&quot;">​</a></h4><p>将mesh划分为更精细的Cluster（例如一个Cluster包含64个三角形），以实现更加精细的控制。每个cluster都有自己的bounding box。</p><h4 id="pipeline" tabindex="-1">Pipeline <a class="header-anchor" href="#pipeline" aria-label="Permalink to &quot;Pipeline&quot;">​</a></h4><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/Unreal_Engine_Nanite_1.png" alt=""></p><h4 id="gpu-instance-culling" tabindex="-1">GPU Instance Culling <a class="header-anchor" href="#gpu-instance-culling" aria-label="Permalink to &quot;GPU Instance Culling&quot;">​</a></h4><p>将cluster组合为chunk（64个cluster组合为一个chunk）</p><h4 id="cluster-group" tabindex="-1">Cluster Group <a class="header-anchor" href="#cluster-group" aria-label="Permalink to &quot;Cluster Group&quot;">​</a></h4><p>由于如果按照簇来减面，就要保证簇与簇的边界是贴合的，这样可能会导致会出现孔洞，如果锁住边来减面，又可能会导致边界处的面片过多，所以nanite采用了<strong>cluster group</strong>的概念，将多个cluster组合在一起，然后再进行减面。 <strong>簇组和簇组之间的边界是锁定的</strong>，减面时会将一个簇组内的三角形数量减半，然后将剩下的三角形重新以128(64)为一个单位生成新的簇，新的簇组成新的簇组，再进行锁边减面。 在进行渲染时，会给同一波三角形形成的簇组选择同一个lod进行渲染。簇组和簇组之间的边界只在两级lod之间锁定，保证lod只有一级差距。 各级LOD、Cluster、Cluster Group之间的关系，如下图所示：</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/Unreal_Engine_Nanite_2.png" alt=""></p><h4 id="lod选择标准" tabindex="-1">lod选择标准 <a class="header-anchor" href="#lod选择标准" aria-label="Permalink to &quot;lod选择标准&quot;">​</a></h4><p>除了考虑距离和覆盖面积这样的参数，还需要考虑形状对于观感的影像。</p><p>可以利用二次曲面误差度量，计算两个lod之间的形态误差，通过这个形态误差，可以在计算出何种距离不会导致人眼看的出来的形态误差，并在这个距离内切换合适的lod。</p><h4 id="lod的选择操作" tabindex="-1">LOD的选择操作 <a class="header-anchor" href="#lod的选择操作" aria-label="Permalink to &quot;LOD的选择操作&quot;">​</a></h4><p>模型的簇会组织成有向无环图，进行选择时，会从图的根部开始，一层一层去找更精细的簇，满足要求就停止搜索。</p><h4 id="三角形绘制" tabindex="-1">三角形绘制 <a class="header-anchor" href="#三角形绘制" aria-label="Permalink to &quot;三角形绘制&quot;">​</a></h4><p>nanite选择的精细程度，很多都是像素大小的三角形，这些小三角形使用硬件光栅化的速度很慢，每个三角形可能都需要和屏幕上的每个像素进行计算。 绘制<strong>小三角形</strong>可以使用computer shader进行软光栅 绘制<strong>大三角形</strong>使用硬件光栅。</p><h4 id="遮挡剔除" tabindex="-1">遮挡剔除 <a class="header-anchor" href="#遮挡剔除" aria-label="Permalink to &quot;遮挡剔除&quot;">​</a></h4><p><strong>层级深度缓冲(Hierarchical Z Buffer)</strong>:可以用来进行遮挡剔除的判断。每一级深度缓冲都是上一级长宽的一半。<strong>每一级的深度缓冲的深度值都是上一级深度缓冲对应四个像素中最深的一个</strong>。 <strong>层级深度缓冲的使用</strong>：会根据物体包围盒所占据的像素个数，选择合适的深度缓冲层级，然后对合适的深度缓冲进行四次采样，就可以判断其是否被遮挡。</p><p>但是没有进行场景绘制时，没有深度缓冲。</p><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/img/Unreal_Engine_Nanite_3.png" alt=""></p><p>因此采用了上一帧的深度缓冲，对这一帧的物体进行遮挡剔除。然后将可见的物体进行绘制。然后再利用这一阵的的深度缓冲，对被剔除的再进行一次测试，再次绘制可见物体。</p><h4 id="绘制" tabindex="-1">绘制 <a class="header-anchor" href="#绘制" aria-label="Permalink to &quot;绘制&quot;">​</a></h4><p>三角形被光栅化绘制后，会绘制到visibility buffer中，这个buffer中存储了每个像素的深度值和对应的簇的id以及簇内的三角形的id。</p><p>将材质的编号编码成深度值，写入深度缓冲区，然后在shader中读取深度值，解码出材质的id，然后根据id读取材质的信息。</p><h4 id="延迟材质" tabindex="-1">延迟材质 <a class="header-anchor" href="#延迟材质" aria-label="Permalink to &quot;延迟材质&quot;">​</a></h4><p>从GPU的角度看，主要分为三个Pass</p><ol><li><p>Material Depth Pass 根据v-buffer获取MaterialID，转换为MaterialSlot，根据MaterialSlot生成Material Depth。写入Material Depth中（32位深度）</p></li><li><p>Material Classify Pass 将屏幕划分为固定大小的Tile，记录每个材质对应的Tile，这一步本质是进行Tile级别的剔除，经过这一步操作之后，每个材质能确定它存在于哪一个Tile，在材质绘制时，只对该Tile的材质进行绘制。</p></li><li><p>Material Rendering Pass 遍历每个材质，绘制材质所在的Tile，同时将z设置为浮点形式的Material Depth，使用第一步生成的Material Depth作为z-buffer，将比较函数设置为相等，以此实现像素精度的剔除。</p></li></ol>',29)])])}const g=e(i,[["render",l]]);export{c as __pageData,g as default};
